head.script:
//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 서버 오늘 일자
    scwin.toDay = $c.date.getServerDateTime("yyyyMMdd");

    // 세션 정보
    scwin.sessionInfo = $c.data.getMemInfo();
    scwin.userClsCd = $c.gus.cfIsNull(scwin.sessionInfo.userClsCd) ? "" : scwin.sessionInfo.userClsCd;
    scwin.userLobranCd = $c.gus.cfIsNull(scwin.sessionInfo.lobranCd) ? "" : scwin.sessionInfo.lobranCd;
    scwin.sysAdminYn = scwin.sessionInfo.sysAdminYn;

    // 기타 전역 변수 셋팅


    // 공통코드 : onPageLoad 에 위치
    const codeOptions = [
        {
            grpCd: "OP317",
            compID: "lc_wrkPlCd"
        } // 오더종류
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);

};

//-------------------------------------------------------------------------
// 데이타 로드 이후(공통코드 필터링용)
//-------------------------------------------------------------------------
scwin.ondataload = async function (e) {
    // 각 콤보박스 초기값 셋팅

    lc_selDate.setSelectedIndex(0);
    lc_forceYn.setSelectedIndex(1);
    lc_selfClsCd.setSelectedIndex(0);

    // 로그인부서로 CY셋팅
    if (scwin.userLobranCd == "4AA") {
        lc_wrkPlCd.setValue("4C01"); // 항동(아니면 바꿔야함)
    } else if (scwin.userLobranCd == "4BB") {
        lc_wrkPlCd.setValue("4C02"); // 의왕 
    } else if (scwin.userLobranCd == "5AA") {
        lc_wrkPlCd.setValue("5C08"); // 광주(아니면 바꿔야함)
    } else {
        lc_wrkPlCd.setValue("4C02"); // 의왕
    }

    // 관리자 여부에 따른 초기 셋팅
    if (scwin.sysAdminYn == "1") {
        $c.gus.cfEnableObj(lc_wrkPlCd, true);
    } else {
        $c.gus.cfEnableObj(lc_wrkPlCd, false);
    }

    $c.gus.cfEnableObj(lc_selDate, false);

    let wrkPlCd = lc_wrkPlCd.getValue();

    // 작업장 블럭 Lookup Data 조회
    scwin.f_getBlockInfo(wrkPlCd);
    // 컨테이너 Lookup Data 조회
    scwin.f_getCntrInfo(wrkPlCd);
    await scwin.f_settingDate();

};

//-------------------------------------------------------------------------
// 작업장 블럭 Lookup Data 조회
//-------------------------------------------------------------------------
scwin.f_getBlockInfo = function (wrkPlCd) {

    // 작업장 블럭정보 조회
    ds_block.removeAll();
    sbm_block.action = "/cm.zz.RetrieveComboCMD.do?sysCd=DsCommonEBC&queryId=retrieveMngBlockList&param1=" + wrkPlCd;
    $c.sbm.execute(sbm_block);

};

//-------------------------------------------------------------------------
// 컨테이너정보 Lookup Data 조회
//-------------------------------------------------------------------------
scwin.f_getCntrInfo = function (wrkPlCd) {
    //컨테이너Siz 정보 조회
    ds_cntrSiz.removeAll();
    sbm_cntrSiz.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101&fltrCd1=" + wrkPlCd;
    $c.sbm.execute(sbm_cntrSiz);

    //컨테이너Typ 정보 조회
    ds_cntrTyp.removeAll();
    sbm_cntrTyp.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102&fltrCd1=" + wrkPlCd;
    $c.sbm.execute(sbm_cntrTyp);

};

//-------------------------------------------------------------------------
// 컨테이너 사이즈 Lookup Data 조회 완료
//-------------------------------------------------------------------------
scwin.sbm_cntrSiz_submitdone = function (e) {
    for (let i = 0; i < ds_cntrSiz.getRowCount(); i++) {
		ds_cntrSiz.setCellData(i, "cdNm", ds_cntrSiz.getCellData(i, "cd"));
	}
};

//-------------------------------------------------------------------------
// 컨테이너 유형 Lookup Data 조회 완료
//-------------------------------------------------------------------------
scwin.sbm_cntrTyp_submitdone = function (e) {
    for (let i = 0; i < ds_cntrTyp.getRowCount(); i++) {
		ds_cntrTyp.setCellData(i, "cdNm", ds_cntrTyp.getCellData(i, "cd"));
	}
};

//-------------------------------------------------------------------------
// 조회조건 일자 셋팅
//-------------------------------------------------------------------------
scwin.f_settingDate = function () {
    ed_onReqFromDt.setValue(scwin.toDay);
    ed_onReqToDt.setValue(scwin.toDay);

};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    $c.sbm.execute(sbm_retrieve);

};

//-------------------------------------------------------------------------
// 조회 성공 후
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if ($c.gus.cfCheckCreateFlag()) {
        $c.gus.cfTurnCreateFlag(false);
    } else {
        // cfHideDSWaitMsg(gr_result);      
        if (ds_result.getRowCount() == 0) {
            $c.gus.f_cfAlertMsg("조회된 데이터가 없습니다");
        } else {
            spn_totRow.setValue(ds_result.getRowCount());
	    }
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (ds_result.getModifiedIndex().length < 1) {
        $c.gus.f_cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!await scwin.f_checkValid()) {
        return;
    }

    let deletedIndexes = ds_result.getDeletedIndex();
    for (let i = 0; i < deletedIndexes.length; i++) {
        let rowIndex = deletedIndexes[i];
        if (ds_result.getCellData(rowIndex, "wrkStsCd") == "F") {
            $c.gus.f_cfAlertMsg("상하차작업 종료건은 수정/삭제할 수 없습니다.");
            ds_result.undoRow(rowIndex);
            ds_result.setRowPosition(rowIndex);
            return;
        }
    }

    if (ds_result.getCellData(ds_result.getRowPosition(), "wrkStsCd") == "F") {
        $c.gus.f_cfAlertMsg("상하차작업 종료건은 수정/삭제할 수 없습니다.");
        ds_result.undoRow(ds_result.getRowPosition());
        return;
    }

    let ret = await $c.win.confirm("저장을 진행 하시겠습니까?");
    if (ret) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 저장 시 유효성 체크
//-------------------------------------------------------------------------
scwin.f_checkValid = function () {
    for (let rowIndex = 0; rowIndex < ds_result.getRowCount(); rowIndex++ ) {
        let displayRowIndex = rowIndex + 1;
    	if (
            ds_result.getRowStatus(rowIndex) == "C"	//입력
    	|| ds_result.getRowStatus(rowIndex) == "U"	//수정
    	) {
	        if (ds_result.getCellData(rowIndex, "impExpClsCd") == "") {
	            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 수출/입 여부를 선택하셔야 합니다.");
	            return false;
	        }

	        if (ds_result.getCellData(rowIndex, "crryinoutClsCd") == "") {
	            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 구분을 선택하셔야 합니다.");
	            return false;
	        }

	        //광주CY는 필수입력 확인 안하는 항목.
	        //2015.09.11 hurrah
	        if (lc_wrkPlCd.getValue() != "5C08") {
		        if (ds_result.getCellData(rowIndex, "cntrSizCd") =="") {
		            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 컨테이너 SIZE 값을 입력하셔야 합니다.");
		            return false;
		        }

		        if (ds_result.getCellData(rowIndex, "cntrTypCd")=="") {
		            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 컨테이너 TYPE 값을 입력하셔야 합니다.");
		            return false;
		        }

		        if (ds_result.getCellData(rowIndex, "lineCd") =="") {
		            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 LINE 값을 입력하셔야 합니다.");
		            return false;
		        }
	        }

	        if (ds_result.getCellData(rowIndex, "fullEmptyClsCd") == "") {
	            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 FULL/EMPTY 값을 입력하셔야 합니다.");
	            return false;
	        }

	        if (
                lc_wrkPlCd.getValue() == "5C08"				// 광주CY 강제등록시 SEAL번호 필수입력 체크. 2015.08.27
	        && ds_result.getCellData(rowIndex, "sealNo") == ""
	        ) {

	            if (
                    ds_result.getCellData(rowIndex, "impExpClsCd")=="O" 
	            && ds_result.getCellData(rowIndex, "fullEmptyClsCd") == "E" 
	            && ds_result.getCellData(rowIndex, "crryinoutClsCd") == "O")	// 수출 엠티 반출
	            {
		            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 SEAL 번호를 입력하셔야 합니다.");
		            return false;
	            }
	        }

	        if (ds_result.getCellData(rowIndex, "vehclNo") == "") {
	            $c.gus.f_cfAlertMsg(displayRowIndex + "행에 차량번호를 입력하셔야 합니다.");
	            return false;
	        }
    	}
    }

    return true;
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = function () {
    let rowIndex = ds_result.getRowPosition();
    if(rowIndex === null){
        return;
    }
    if (ds_result.getCellData(rowIndex, 'onoffNo') == "") {
        $c.gus.f_cfAlertMsg("강제등록건이 아니어서 삭제 할 수 없습니다");
        $c.data.undoRow(ds_result, "Y");
        return;
    }

    ds_result.deleteRow(rowIndex);
}

//-------------------------------------------------------------------------
// 행복사
//-------------------------------------------------------------------------
scwin.f_copyRow = function () {
	let rowIndex = ds_result.getRowPosition();
    if (!$c.gus.cfIsNull(rowIndex)) {
        let insertIndex = ds_result.insertRow();
        ds_result.setCellData(insertIndex, "wrkPlCd", ds_result.getCellData(rowIndex, "wrkPlCd"));
        ds_result.setCellData(insertIndex, "impExpClsCd", ds_result.getCellData(rowIndex, "impExpClsCd"));
        ds_result.setCellData(insertIndex, "crryinoutClsCd", ds_result.getCellData(rowIndex, "crryinoutClsCd"));
        ds_result.setCellData(insertIndex, "selfClsCd", ds_result.getCellData(rowIndex, "selfClsCd"));
        ds_result.setCellData(insertIndex, "cntrNo", ds_result.getCellData(rowIndex, "cntrNo"));
        ds_result.setCellData(insertIndex, "cntrSizCd", ds_result.getCellData(rowIndex, "cntrSizCd"));
        ds_result.setCellData(insertIndex, "cntrTypCd", ds_result.getCellData(rowIndex, "cntrTypCd"));
        ds_result.setCellData(insertIndex, "fullEmptyClsCd", ds_result.getCellData(rowIndex, "fullEmptyClsCd"));
        ds_result.setCellData(insertIndex, "blNo", ds_result.getCellData(rowIndex, "blNo"));
        ds_result.setCellData(insertIndex, "bookingNo", ds_result.getCellData(rowIndex, "bookingNo"));
        ds_result.setCellData(insertIndex, "lineCd", ds_result.getCellData(rowIndex, "lineCd"));
        ds_result.setCellData(insertIndex, "wrkMemo", ds_result.getCellData(rowIndex, "wrkMemo"));
        ds_result.setCellData(insertIndex, "blckCd", ds_result.getCellData(rowIndex, "blckCd"));
        ds_result.setCellData(insertIndex, "forceYn", "1");
        ds_result.setCellData(insertIndex, "crryinoutIntendDt", scwin.toDay);
    }
}

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_addRow = function () {
    let rowIndex = ds_result.getRowPosition();
    if (ds_result.getRowCount() > 0) {
        ds_result.insertRow(); 
        ds_result.setCellData(rowIndex, "wrkPlCd", lc_wrkPlCd.getValue());
        ds_result.getCellData(rowIndex, "forceYn", "1");

        //광주CY는 당사, 수출, 상차로 기본세팅
        //2015.09.11 hurrah
        if (lc_wrkPlCd.getValue() == "5C08") {
            ds_result.setCellData(rowIndex, "impExpClsCd", "O");
            ds_result.setCellData(rowIndex, "crryinoutClsCd", "O");
        }

        ds_result.setCellData(rowIndex, "selfClsCd", "L");
    }
}

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_deleteRow = function () {
    let rowIndex = ds_result.getRowPosition();
    if (ds_result.getRowCount() > 0) {
        if (ds_result.getRowStatus(rowIndex) == "C") {
            ds_result.removeRow(rowIndex);
        } else {
            ds_result.deleteRow(rowIndex); 
        }
    }
}       

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_undoRow = function () {  
    $c.data.undoRow(ds_result, "Y");
}

//-------------------------------------------------------------------------
// 저장 성공 후
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = function (e) {
    $c.gus.f_cfAlertMsg("적용 되었습니다.");
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 그리드내 차량 조회 시 팝업 open
//-------------------------------------------------------------------------
scwin.f_retrieveVehclInGrid = async function () {
    let row = ds_result.getRowPosition();
    let data = {
        vehclShortNo: ds_result.getCellData(row, "vehclNo"),
        whereAreYouFrom: "T",
        callbackFn: scwin.f_retrieveVehclInGrid_callback
    };

    let opts = {
        id: "pop_retrieveVehclI",
        popupName: "차량정보",
        width: "930px",
        height: "500px"
    };

    let ret = await $c.win.openPopup("/ui/tn/op/transwrkindict/cntr/tn_304_01_05p.xml", opts, data);
};

//-------------------------------------------------------------------------
// 그리드내 차량 조회 시 팝업 open 후 callback
//-------------------------------------------------------------------------
scwin.f_retrieveVehclInGrid_callback = function (rtnList) {
    // TODO: 차량 조회 팝업 스크립트 오류로 팝업창으로부터 데이터 받았을 경우 확인 불가
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        ds_result.setCellData(ds_result.getRowPosition(), "vehclNo", rtnList[1]);
    }
};

//-------------------------------------------------------------------------
// 그리드내 데이터 변경 시(scwin.gr_result_onafteredit 이벤트 참조)
//-------------------------------------------------------------------------
scwin.f_retrieveBlockInfo = function (line, siz, typ, row, clscd) {
    ds_op316Info.removeAll();
  	var qStr = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=NcallCommonEBC"+
  	                      "&queryId=retrieveCyBlockInfo"+
  	                      "&param1="+lc_wrkPlCd.getValue()+
  	                      "&param2="+line+
  	                      "&param3="+siz+
  	                      "&param4="+typ+
  	                      "&param5="+ds_result.getCellData(row, "fullEmptyClsCd")+
  	                      "&param6="+clscd;

    sbm_retrieveBlockInfo.action = qStr;
    // submitdone에서 row를 받아 줄 방법이 없어서 사용한 변수
    scwin.row = row;
  	$c.sbm.execute(sbm_retrieveBlockInfo);
};

//-------------------------------------------------------------------------
// 그리드내 데이터 변경 시 조회 성공
//-------------------------------------------------------------------------
scwin.sbm_retrieveBlockInfo_submitdone = function (e) {
    if (ds_op316Info.getRowCount() > 0) {
  		ds_result.setCellData(scwin.row, "blckCd", ds_op316Info.getCellData(0, "col1"));
  	} else {
  		if(ds_result.getCellData(scwin.row, "wrkPlCd") == "5C08") {
  			ds_result.setCellData(scwin.row, "blckCd",  "A1");
  		}
    }
    // 다 사용 후 기존 row는 제거
    scwin.row = "";
};

//-------------------------------------------------------------------------
// CY상하차진행현황 화면 open
//-------------------------------------------------------------------------
scwin.f_openOnoffInfo = async function () {
    let paramObj = {};
    $c.win.openMenu("CY상하차진행현황", "/ui/tn/op/transwrkindict/cntr/tn_304_03_06b.xml", "tn_304_03_06b.jsp", paramObj);
};

//-------------------------------------------------------------------------
// CY로케이션관리 화면 open
//-------------------------------------------------------------------------
scwin.f_openLocationInfo = function () {
    let paramObj = {};
    $c.win.openMenu("CY로케이션관리", "/ui/tn/op/transwrkindict/cntr/tn_304_03_07b.xml", "tn_304_03_07b.jsp", paramObj);
};

//-------------------------------------------------------------------------
// CY후불정산거래처관리 화면 open
//-------------------------------------------------------------------------
scwin.f_clntInfo = function () {
    let paramObj = {};
    $c.win.openMenu("CY후불정산거래처관리", "/ui/tn/op/transwrkindict/cntr/tn_304_03_08b.xml", "tn_304_03_08b.jsp", paramObj);
};

//-------------------------------------------------------------------------
// 그리드 칼럼 강제등록 displayFormatter
//-------------------------------------------------------------------------
scwin.gridForceYnDisplayFormatter = function (value) {
    switch (value) {
        case "1":
            return "Y";

        case "2":
            return "J";

        default:
            return "N";
    }
}

//-------------------------------------------------------------------------
// 작업장 onchange
//-------------------------------------------------------------------------
scwin.lc_wrkPlCd_onchange = function (info) {
    if (info.newValue == "5C08") {
        gr_result.setColumnOrder(
            [
                "wrkPlCd",
                "crryinoutIntendNo",
                "crryinoutIntendHh",
                "impExpClsCd",
                "arrvlportDtm",
                "crryinoutClsCd",
                "cntrNo",
                "cntrSizCd",
                "cntrTypCd",
                "fullEmptyClsCd",
                "sealNo",
                "lineCd",
                "blckCd",
                "wrkMemo",
                "wt",
                "selfClsCd",
                "vehclNo",
                "vehclIdCardNo",
                "odrNo",
                "cntrSeq",
                "wrkPathSeq",
                "wrkStpSeq",
                "crryinoutIntendDt",
                "selfTransCoClntNo",
                "blNo",
                "bookingNo",
                "cnclDtm",
                "cnclPicId",
                "forceYn",
                "onoffNo",
                "wrkStsCd"
            ]
        );
    } else {
        gr_result.setColumnOrder(
            [
                "wrkPlCd",
                "crryinoutIntendNo",
                "crryinoutIntendHh",
                "impExpClsCd",
                "arrvlportDtm",
                "crryinoutClsCd",
                "cntrNo",
                "cntrSizCd",
                "cntrTypCd",
                "fullEmptyClsCd",
                "sealNo",
                "wt",
                "selfClsCd",
                "vehclNo",
                "vehclIdCardNo",
                "odrNo",
                "cntrSeq",
                "wrkPathSeq",
                "wrkStpSeq",
                "crryinoutIntendDt",
                "selfTransCoClntNo",
                "blNo",
                "bookingNo",
                "lineCd",
                "blckCd",
                "cnclDtm",
                "cnclPicId",
                "wrkMemo",
                "forceYn",
                "onoffNo",
                "wrkStsCd"
            ]
        );
    }
};

//-------------------------------------------------------------------------
// 그리드 onafteredit
//-------------------------------------------------------------------------
scwin.gr_result_onafteredit = function (rowIndex, columnIndex, value) {
    let colId = ds_result.getColumnID(columnIndex);
    switch (colId) {
        case "vehclNo":
		  	// 광주CY인 경우만 이벤트 발생. seal, full/empty 구분값만  넣고 저장하는경우
		  	// 라인코드 이벤트가 안먹기 때문에 차량번호에 이벤트 발생하도록 변경.
		  	// 2015.09.11 hurrah
		  	if (lc_wrkPlCd.getValue( )== "5C08") {
		  		let v_line = ds_result.getCellData(rowIndex, "lineCd");
		  		let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
		  		let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
		  		let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
		  		scwin.f_retrieveBlockInfo(v_line, v_siz, v_typ, rowIndex, v_clsCd);
		  	}
			break;
		case "lineCd":
		  	if (ds_result.getCellData(rowIndex, "lineCd") != "" && ds_result.getCellData(rowIndex, "fullEmptyClsCd")=="E") {
		  		let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
		  		let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
		  		let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
		  		scwin.f_retrieveBlockInfo(ds_result.getCellData(rowIndex, "lineCd"), v_siz, v_typ, rowIndex, v_clsCd);
		  	} else if (ds_result.getCellData(rowIndex, "wrkPlCd") == "5C08") {
		  		let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
		  		let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
		  		let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
		  		scwin.f_retrieveBlockInfo(ds_result.getCellData(rowIndex, "lineCd"), v_siz, v_typ, rowIndex, v_clsCd);
		  	}
			break;
    }
};

//-------------------------------------------------------------------------
// 조회 버튼 왼쪽 휴지통 버튼 onclick
//-------------------------------------------------------------------------
scwin.tbl_search_onclick = async function (e) {
    await $c.gus.cfInitObjects(grp_search);
    scwin.f_settingDate();
};

scwin.sbm_block_submitdone = function (e) {

    ds_block.setCellData( 0 ,"name", "")
};
